SELECT SUM(balance / POWER(10, 18)) AS total_circulating_supply FROM (SELECT (received.total_received - COALESCE(sent.total_sent, 0)) AS balance FROM (SELECT "to_address", SUM(CAST("value" AS FLOAT)) AS total_received FROM "TOKEN_TRANSFERS" WHERE "to_address" != '0x000...' GROUP BY "to_address") AS received LEFT JOIN (SELECT "from_address", SUM(CAST("value" AS FLOAT)) AS total_sent FROM "TOKEN_TRANSFERS" WHERE "from_address" != '0x000...' GROUP BY "from_address") AS sent ON received."to_address" = sent."from_address");
